prompts/intent_prompt.py"}, "result": "\"\"\"意图识别 Agent 的 system prompt\"\"\"\n\nINTENT_RECOGNITION_PROMPT = \"\"\"你是平安寿险智能助手的意图识别模块。你需要根据用户的提问内容和对话上下文，判断用户的意图类型。\n\n## 意图分类\n\n一共有四种意图，请严格按照以下分类判断：\n\n1. **team_portrait**（队伍画像分析）：用户想了解队伍的人力结构、人力分布、职级分布、队伍画像等信息。\n   - 示例：\"帮我看看队伍画像\"、\"队伍人力分布情况\"、\"当前队伍结构怎样\"\n\n2. **customer_portrait**（客户画像分析）：用户想了解客户的分布、画像、客温客价等信息。\n   - 示例：\"分析一下客户画像\"、\"客户分布情况\"、\"看看客户结构\"\n\n3. **nbev_planning**（NBEV达成路径规划分析）：用户想进行NBEV达成路径的规划、测算或分析，包括从队伍、客户、产品维度分析如何达成NBEV目标。\n   - 示例：\"帮我做NBEV达成规划\"、\"分析一下达成路径\"、\"NBEV目标怎么达成\"、\"帮我做规划分析\"、\"达成路径测算\"\n   - 注意：当用户提供了\"NBEV目标值是xxx万\"或\"规划路径：xxx\"等信息时，也属于此意图。\n\n4. **other**（其他意图）：不属于以上三种意图的其他问题。\n   - 示例：\"今天天气怎样\"、\"帮我写一份报告\"\n\n## 字段提取\n\n当判断意图为 nbev_planning 时，请尝试从用户消息中提取以下字段（如果存在）：\n- target_value：NBEV目标值，单位为\"万\"，只提取数字部分，如用户说\"300万\"则提取\"300\"\n- path_types：达成路径类型，可选值为\"队伍\"、\"客户\"、\"产品\"，提取为列表\n\n### target_value 提取规则\n\n只要用户表达的是 NBEV 目标值，就应尽量提取 target_value，不要因为口语化修饰词而漏提。以下表达都应提取为 target_value=\"300\"：\n\n- \"NBEV目标300万\"\n- \"NBEV目标值是300万\"\n- \"NBEV的目标是300万\"\n- \"NBEV的目标大概300万\"\n- \"NBEV目标约300万\"\n- \"NBEV目标300万左右\"\n- \"目标300万，规划路径：队伍、客户\"\n\n请注意：\n- \"大概\"、\"约\"、\"大约\"、\"差不多\"、\"左右\"、\"预计\"、\"先按\" 这类词不会改变 target_value 的数值提取\n- 即使句子里同时出现路径信息，也要继续提取 target_value，不要因为已经识别出 path_types 就忽略目标值\n- 如果用户明确给出了数字和\"万\"这个单位，优先提取该数字作为 target_value\n- 如果用户没有表达目标值，才返回 null\n\n### path_types 提取规则\n\n- 如果用户提到\"规划路径：队伍、客户\"、\"从队伍和客户两个维度分析\"、\"看队伍、客户路径\"，都应提取为 [\"队伍\", \"客户\"]\n- 只提取实际出现的路径类型，不要臆造未出现的路径\n\n## 注意事项\n\n- 请结合对话上下文进行判断，不要只看当前消息\n- 如果用户的意图不明确，倾向于判断为 other\n- confidence 表示你对判断的确信程度，0-1之间\n- 当意图判断为 nbev_planning 时，应优先完整提取 target_value 和 path_types，避免遗漏必填字段\n- 请严格按照json格式输出\n\n## 新增调整意图\n\n除原有意图外，还需要识别以下NBEV达成路径规划调整类意图：\n\n5. **target_value_adjustment**（目标值调整）：已经完成NBEV目标值达成测算后，用户希望修改目标值并重新测算。示例：\"我要调整目标\"、\"调整目标值\"、\"把目标值改成500万重新测算\"。\n\n6. **achievement_measurement_adjustment**（达成测算调整）：用户已经完成某些路径的达成测算后，想重新测算新的路径。示例：\"规划产品达成路径\"、\"重新测算客户路径\"、\"再看队伍达成路径\"。\n\n7. **nbev_planning_fallback**（NBEV规划兜底）：仍属于NBEV目标值达成路径规划调整范畴，但当前智能体暂不支持的相关能力，例如直接修改达成路径测算中的各种数值、AI研判分析结果等。注意：兜底意图仍属于NBEV目标值达成路径规划范畴；完全超出该范畴的问题才归为 other。\n\"\"\"\n", "tool_call_id": "call_00_6RUh9tldTm9mEOQkeLw07004", "tool_name": "search_source_file"}, {"arguments": {"file_key": "config:ext_repo:app/workflow/steps/intent_recognition.py"}, "result": "\"\"\"Step1: intent recognition.\"\"\"\n\nimport logging\nimport re\nfrom typing import Optional\n\nfrom agno.agent import Agent\nfrom agno.models.openai import OpenAILike\n\nfrom app.config import settings\nfrom app.schemas.intent import IntentResult, IntentType\nfrom app.schemas.request import ContextItem\nfrom app.workflow.path_types import extract_path_types_from_text, extract_target_value_from_text\nfrom app.workflow.prompts.intent_prompt import INTENT_RECOGNITION_PROMPT\n\nlogger = logging.getLogger(__name__)\n\n\ndef _build_model() -> OpenAILike:\n    \"\"\"Build DashScope compatible model instance.\"\"\"\n    return OpenAILike(\n        id=settings.MODEL_ID,\n        api_key=settings.DASHSCOPE_API_KEY,\n        base_url=settings.DASHSCOPE_BASE_URL,\n    )\n\n\n# ---------------------------------------------------------------------------\n# Homepage sample phrases — matched by regex before any LLM call.\n# Each entry is (compiled_regex, IntentType).\n#\n# Ordering matters: customer_portrait rules MUST precede team_portrait so that\n# \"我们团队的客户是怎么分布的\" matches customer, not team.\n# ---------------------------------------------------------------------------\n_HOMEPAGE_RULES: list[tuple[re.Pattern, IntentType]] = [\n    # --- NBEV Planning ---\n    (re.compile(r\"怎么达成.*NBEV.*目标\", re.IGNORECASE), IntentType.nbev_planning),\n    # --- Customer Portrait (before team_portrait) ---\n    (re.compile(r\"客户.*(?:画像|分布|结构|分层)\"), IntentType.customer_portrait),\n    (re.compile(r\"客群.*(?:画像|分布|结构)\"), IntentType.customer_portrait),\n    (re.compile(r\"(?:客温|客价).*(?:分布|画像)\"), IntentType.customer_portrait),\n    # --- Team Portrait ---\n    (re.compile(r\"(?:队伍|团队).*(?:画像|分布|结构|分层|人力)\"), IntentType.team_portrait),\n    (re.compile(r\"人力.*(?:画像|分布|结构)\"), IntentType.team_portrait),\n]\n\n\ndef try_homepage_intent(user_message: str) -> Optional[IntentResult]:\n    \"\"\"Match homepage sample phrases only (Tier 0).\n\n    When matched, the result is *final* — callers should return it\n    directly without LLM supplementation.\n    \"\"\"\n    normalized_message = re.sub(r\"\\s+\", \"\", user_message)\n    for pattern, intent_type in _HOMEPAGE_RULES:\n        if pattern.search(normalized_message):\n            logger.info(\"rule intent matched homepage phrase intent=%s\", intent_type.value)\n            return IntentResult(\n                intent=intent_type,\n                confidence=1.0,\n                target_value=None,\n                path_types=None,\n            )\n    return None\n\n\ndef try_rule_based_intent(\n    user_message: str,\n    contexts: Optional[list[ContextItem]] = None,\n) -> Optional[IntentResult]:\n    \"\"\"Recognize standard NBEV planning messages without calling the LLM.\"\"\"\n    normalized_message = re.sub(r\"\\s+\", \"\", user_message)\n    has_completed_planning_context = _has_completed_planning_context(contexts)\n\n    # --- Tier 1: adjustment intents after a completed NBEV planning round ---\n    if has_completed_planning_context and _is_target_adjustment_message(normalized_message):\n        return IntentResult(\n            intent=IntentType.target_value_adjustment,\n            confidence=1.0,\n            target_value=_extract_target_value_from_contexts(contexts),\n            path_types=None,\n        )\n\n    adjusted_paths = extract_path_types_from_text(user_message) or _extract_path_types_by_keywords(normalized_message)\n    if has_completed_planning_context and adjusted_paths and _is_measurement_adjustment_message(normalized_message):\n        return IntentResult(\n            intent=IntentType.achievement_measurement_adjustment,\n            confidence=1.0,\n            target_value=_extract_target_value_from_contexts(contexts),\n            path_types=adjusted_paths,\n        )\n\n    if has_completed_planning_context and _is_planning_fallback_message(normalized_message):\n        return IntentResult(\n            intent=IntentType.nbev_planning_fallback,\n            confidence=0.95,\n            target_value=_extract_target_value_from_contexts(contexts),\n            path_types=adjusted_paths,\n        )\n\n    # --- Tier 0: homepage sample phrases ---\n    homepage_result = try_homepage_intent(user_message)\n    if homepage_result:\n        return homepage_result\n\n    # --- Tier 2: structured extraction (target_value / path_types) ---\n    target_value = extract_target_value_from_text(user_message)\n    path_types = extract_path_types_from_text(user_message)\n\n    if target_value is not None or path_types is not None:\n        result = IntentResult(\n            intent=IntentType.nbev_planning,\n            confidence=1.0,\n            target_value=target_value,\n            path_types=path_types,\n        )\n        logger.info(\n            \"rule intent matched target_value=%s path_types=%s\",\n            result.target_value,\n            result.path_types,\n        )\n        return result\n\n    # --- Tier 3: keyword heuristic (NBEV + planning keyword) ---\n    has_nbev = \"NBEV\" in normalized_message.upper()\n    has_planning_intent = any(keyword in normalized_message for keyword in (\"达成\", \"规划\", \"路径\", \"测算\", \"分析\"))\n    if has_nbev and has_planning_intent:\n        logger.info(\"rule intent matched generic nbev planning message\")\n        return IntentResult(\n            intent=IntentType.nbev_planning,\n            confidence=0.95,\n            target_value=None,\n            path_types=None,\n        )\n\n    logger.info(\"rule intent not matched\")\n    return None\n\n\ntry_shortcut_intent = try_rule_based_intent\n\n\ndef _contexts_text(contexts: Optional[list[ContextItem]]) -> str:\n    parts: list[str] = []\n    for ctx in contexts or []:\n        if ctx.query:\n            parts.append(ctx.query)\n        if ctx.answer:\n            parts.append(ctx.answer)\n    return \"\\n\".join(parts)\n\n\ndef _has_completed_planning_context(contexts: Optional[list[ContextItem]]) -> bool:\n    text = _contexts_text(contexts)\n    if not text:\n        return False\n    markers = (\n        \"NEXT_STEP_CARD\",\n        \"TEAM_REACH_MEASUREMENT\",\n        \"CUSTOMER_REACH_MEASUREMEN\",\n        \"PRODUCT_REACH_MEASUREMENT\",\n        \"达成路径\",\n        \"达成测算\",\n        \"路径规划\",\n    )\n    return any(marker in text for marker in markers)\n\n\ndef _extract_target_value_from_contexts(contexts: Optional[list[ContextItem]]) -> Optional[str]:\n    text = _contexts_text(contexts)\n    for pattern in (\n        r'\''\"targetNbev\"\\s*:\\s*(\\d+(?:\\.\\d+)?)'\'',\n        r'\''\"target_nbev\"\\s*:\\s*(\\d+(?:\\.\\d+)?)'\'',\n        r'\''\"target_value\"\\s*:\\s*\"?(\\d+(?:\\.\\d+)?)\"?'\'',\n        r\"目标值?[^\\d]*(\\d+(?:\\.\\d+)?)\\s*万\",\n        r\"NBEV目标[^\\d]*(\\d+(?:\\.\\d+)?)\\s*万\",\n    ):\n        match = re.search(pattern, text, re.IGNORECASE)\n        if match:\n            return match.group(1)\n    return extract_target_value_from_text(text)\n\n\ndef _is_target_adjustment_message(normalized_message: str) -> bool:\n    return any(\n        keyword in normalized_message\n        for keyword in (\"调整目标\", \"修改目标\", \"重设目标\", \"重新设置目标\", \"换个目标\")\n    )\n\n\ndef _extract_path_types_by_keywords(normalized_message: str) -> Optional[list[str]]:\n    paths: list[str] = []\n    if \"队伍\" in normalized_message or \"团队\" in normalized_message:\n        paths.append(\"队伍\")\n    if \"客户\" in normalized_message:\n        paths.append(\"客户\")\n    if \"产品\" in normalized_message:\n        paths.append(\"产品\")\n    return paths or None\n\n\ndef _is_measurement_adjustment_message(normalized_message: str) -> bool:\n    return any(keyword in normalized_message for keyword in (\"重新测算\", \"重新规划\", \"规划\", \"测算\")) and any(\n        path in normalized_message for path in (\"队伍\", \"团队\", \"客户\", \"产品\")\n    )\n\n\ndef _is_planning_fallback_message(normalized_message: str) -> bool:\n    if not any(keyword in normalized_message for keyword in (\"调整\", \"修改\", \"改\", \"AI研判\", \"研判\", \"分析结果\", \"达成路径\", \"测算\")):\n        return False\n    return any(keyword in normalized_message for keyword in (\"NBEV\", \"目标\", \"路径\", \"测算\", \"队伍\", \"团队\", \"客户\", \"产品\", \"分布\", \"研判\"))\n\n\nasync def recognize_intent(\n    user_message: str,\n    contexts: Optional[list[ContextItem]] = None,\n) -> IntentResult:\n    \"\"\"Call LLM Agent for intent recognition.\"\"\"\n    context_str = \"\"\n    if contexts:\n        context_parts = []\n        for ctx in contexts:\n            if ctx.query:\n                context_parts.append(f\"用户: {ctx.query}\")\n            if ctx.answer:\n                context_parts.append(f\"助手: {ctx.answer}\")\n        if context_parts:\n            context_str = \"\\n\\n## 对话上下文\\n\" + \"\\n\".join(context_parts)\n\n    agent = Agent(\n        name=\"IntentRecognizer\",\n        model=_build_model(),\n        instructions=INTENT_RECOGNITION_PROMPT,\n        output_schema=IntentResult,\n        markdown=False,\n        telemetry=False,\n    )\n\n    prompt = f\"用户消息：{user_message}{context_str}\"\n    logger.info(\"llm intent recognition started context_count=%s\", len(contexts or []))\n    response = await agent.arun(prompt)\n\n    if response and response.content and isinstance(response.content, IntentResult):\n        logger.info(\n            \"llm intent recognition finished intent=%s confidence=%s\",\n            response.content.intent,\n            response.content.confidence,\n        )\n        return response.content\n\n    logger.warning(\"llm intent recognition returned empty content, fallback to other\")\n    return IntentResult(intent=IntentType.other, confidence=0.5)\n", "tool_call_id": "call_01_DlZq7gJOlME8CmmuApxW0767", "tool_name": "search_source_file"}, {"arguments": {"file_key": "config:ext_repo:app/config.py"}, "result": "\"\"\"Application configuration and logging setup.\"\"\"\n\nfrom __future__ import annotations\n\nimport json\nimport logging\nimport os\nimport re\nfrom dataclasses import dataclass, field\nfrom logging.handlers import TimedRotatingFileHandler\nfrom pathlib import Path\nfrom typing import Any\n\nfrom dotenv import load_dotenv\n\nload_dotenv()\n\nBASE_DIR = Path(__file__).resolve().parent\nCONFIG_DIR = BASE_DIR / \"configs\"\nSUPPORTED_ENV_TYPES = {\"dev\", \"stg\", \"prd\"}\nSUPPORTED_SESSION_STORE_CLEANUP_MODES = {\"explicit\", \"ttl\", \"hybrid\"}\n\n\n@dataclass(frozen=True)\nclass AppSettings:\n    ENV_TYPE: str = \"dev\"\n    DASHSCOPE_API_KEY: str = \"\"\n    MODEL_ID: str = \"qwen3-next-80b-a3b-instruct\"\n    DASHSCOPE_BASE_URL: str = \"https://dashscope.aliyuncs.com/compatible-mode/v1\"\n    SESSION_STORE_DIR: str = \"data/session-store\"\n    SESSION_STORE_CLEANUP_MODE: str = \"hybrid\"\n    SESSION_STORE_TTL_SECONDS: int = 1200\n    LOG_DIR: str = \"logs\"\n    LOG_FILE_NAME: str = \"marketing-planning.log\"\n    LOG_LEVEL: str = \"INFO\"\n    LOG_FORMAT: str = \"%(asctime)s %(levelname)s [%(name)s] %(message)s\"\n    LOG_BACKUP_COUNT: int = 14\n    SSE_EVENTS: dict[str, str] = field(default_factory=dict)\n    INTENT_MAPPING: dict[str, dict[str, str]] = field(default_factory=dict)\n    PATH_ORDER: tuple[str, ...] = (\"队伍\", \"客户\", \"产品\")\n    THINK_TEMPLATES: dict[str, str] = field(default_factory=dict)\n    CARD_METADATA: dict[str, dict[str, str]] = field(default_factory=dict)\n    RECOMMEND_QUESTIONS: tuple[str, ...] = ()\n    DORIS_CONFIG: dict[str, str] = field(default_factory=dict)\n\n\ndef _load_env_config(env_type: str) -> dict[str, Any]:\n    config_path = CONFIG_DIR / f\"config_{env_type}.json\"\n    with config_path.open(\"r\", encoding=\"utf-8\") as file:\n        return json.load(file)\n\n\ndef _parse_positive_int(value: Any, field_name: str) -> int:\n    if isinstance(value, bool):\n        raise ValueError(f\"{field_name} must be a positive integer\")\n\n    if isinstance(value, int):\n        parsed_value = value\n    elif isinstance(value, str) and re.fullmatch(r\"[+]?\\d+\", value.strip()):\n        parsed_value = int(value.strip())\n    else:\n        raise ValueError(f\"{field_name} must be a positive integer\")\n\n    if parsed_value <= 0:\n        raise ValueError(f\"{field_name} must be a positive integer\")\n\n    return parsed_value\n\n\ndef _validate_settings(values: dict[str, Any]) -> dict[str, Any]:\n    cleanup_mode = str(\n        values.get(\"SESSION_STORE_CLEANUP_MODE\", AppSettings.SESSION_STORE_CLEANUP_MODE)\n    ).strip().lower()\n    if cleanup_mode not in SUPPORTED_SESSION_STORE_CLEANUP_MODES:\n        raise ValueError(\n            \"SESSION_STORE_CLEANUP_MODE must be one of \"\n            f\"{sorted(SUPPORTED_SESSION_STORE_CLEANUP_MODES)}\"\n        )\n    values[\"SESSION_STORE_CLEANUP_MODE\"] = cleanup_mode\n    values[\"SESSION_STORE_TTL_SECONDS\"] = _parse_positive_int(\n        values.get(\"SESSION_STORE_TTL_SECONDS\", AppSettings.SESSION_STORE_TTL_SECONDS),\n        \"SESSION_STORE_TTL_SECONDS\",\n    )\n    return values\n\n\ndef _build_settings() -> AppSettings:\n    env_type = os.getenv(\"ENV_TYPE\", \"dev\").lower()\n    if env_type not in SUPPORTED_ENV_TYPES:\n        env_type = \"dev\"\n\n    values = _load_env_config(env_type)\n    values[\"ENV_TYPE\"] = env_type\n\n    # Runtime environment variables can override deploy-time JSON config.\n    override_keys = (\n        \"DASHSCOPE_API_KEY\",\n        \"MODEL_ID\",\n        \"DASHSCOPE_BASE_URL\",\n        \"SESSION_STORE_DIR\",\n        \"SESSION_STORE_CLEANUP_MODE\",\n        \"SESSION_STORE_TTL_SECONDS\",\n        \"LOG_DIR\",\n        \"LOG_FILE_NAME\",\n        \"LOG_LEVEL\",\n        \"LOG_FORMAT\",\n    )\n    for key in override_keys:\n        env_value = os.getenv(key)\n        if env_value is not None:\n            values[key] = env_value\n\n    values[\"PATH_ORDER\"] = tuple(values.get(\"PATH_ORDER\", (\"队伍\", \"客户\", \"产品\")))\n    values[\"RECOMMEND_QUESTIONS\"] = tuple(values.get(\"RECOMMEND_QUESTIONS\", ()))\n    values = _validate_settings(values)\n\n    return AppSettings(**values)\n\n\ndef init_logger() -> None:\n    \"\"\"Initialize root logger with daily log rotation.\"\"\"\n    root_logger = logging.getLogger()\n    if getattr(root_logger, \"_marketing_planning_initialized\", False):\n        return\n\n    log_dir = Path(settings.LOG_DIR)\n    log_dir.mkdir(parents=True, exist_ok=True)\n    log_file_path = log_dir / settings.LOG_FILE_NAME\n\n    formatter = logging.Formatter(settings.LOG_FORMAT)\n    level = getattr(logging, settings.LOG_LEVEL.upper(), logging.INFO)\n\n    file_handler = TimedRotatingFileHandler(\n        filename=log_file_path,\n        when=\"D\",\n        interval=1,\n        backupCount=settings.LOG_BACKUP_COUNT,\n        encoding=\"utf-8\",\n    )\n    file_handler.setFormatter(formatter)\n    file_handler.setLevel(level)\n\n    console_handler = logging.StreamHandler()\n    console_handler.setFormatter(formatter)\n    console_handler.setLevel(level)\n\n    root_logger.setLevel(level)\n    root_logger.handlers.clear()\n    root_logger.addHandler(file_handler)\n    root_logger.addHandler(console_handler)\n    root_logger._marketing_planning_initialized = True\n\n    logging.getLogger(__name__).info(\n        \"logger initialized env_type=%s log_file=%s level=%s\",\n        settings.ENV_TYPE,\n        log_file_path,\n        settings.LOG_LEVEL,\n    )\n\n\nsettings = _build_settings()\n\n# Backward-compatible class-style access for older utility code.\nSettings = AppSettings\n", "tool_call_id": "call_02_GHVVhkWzE0u67xI94ZVi0797", "tool_name": "search_source_file"}, {"arguments": {"file_key": "config:ext_repo:app/schemas/intent.py"}, "result": "from enum import Enum\nfrom typing import Optional\n\nfrom pydantic import BaseMod